import{_ as c,r as f,i as p,j as x,c as m,a as o,e as g,o as h}from"./CfIHfp8L.js";import{u}from"./CFVSkyx-.js";const b={class:"kanit-font bg-gray-50"},y={class:"scroll-indicator"},w={__name:"terms-of-service",setup(k){u({title:"ข้อตกลงและเงื่อนไขการใช้บริการ - ไปนำแหน่",htmlAttrs:{lang:"th"},link:[{rel:"preconnect",href:"https://fonts.googleapis.com"},{rel:"preconnect",href:"https://fonts.gstatic.com",crossorigin:""},{rel:"stylesheet",href:"https://fonts.googleapis.com/css2?family=Kanit:wght@300;400;500;600;700&display=swap"}]});const e=f(null),s=()=>{const d=document.documentElement,a=d.scrollHeight-d.clientHeight,r=window.scrollY,n=a>0?r/a*100:0;e.value&&(e.value.style.width=`${n}%`);const i=Array.from(document.querySelectorAll(".content-section"));let l="";i.forEach(t=>{const v=t.offsetTop;window.scrollY>=v-120&&(l=t.getAttribute("id")||"")}),Array.from(document.querySelectorAll(".toc-link")).forEach(t=>{t.classList.toggle("active",t.getAttribute("href")===`#${l}`)})};return p(()=>{window.addEventListener("scroll",s,{passive:!0}),s()}),x(()=>{window.removeEventListener("scroll",s)}),(d,a)=>(h(),m("div",b,[o("div",y,[o("div",{class:"scroll-progress",ref_key:"scrollProgressEl",ref:e},null,512)]),a[0]||(a[0]=g('<div class="px-4 py-8 mx-auto max-w-7xl sm:px-6 lg:px-8" data-v-97317e6f><div class="grid grid-cols-1 gap-8 lg:grid-cols-4" data-v-97317e6f><div class="lg:col-span-1" data-v-97317e6f><div class="sticky p-6 bg-white rounded-lg shadow-md top-24" data-v-97317e6f><h3 class="mb-4 text-lg font-semibold text-gray-900" data-v-97317e6f>สารบัญ</h3><nav class="space-y-2" data-v-97317e6f><a href="#section-1" class="block px-3 py-2 text-sm text-gray-600 rounded-md toc-link hover:text-blue-600" data-v-97317e6f> 1. บทนำ </a><a href="#section-2" class="block px-3 py-2 text-sm text-gray-600 rounded-md toc-link hover:text-blue-600" data-v-97317e6f> 2. คำจำกัดความ </a><a href="#section-3" class="block px-3 py-2 text-sm text-gray-600 rounded-md toc-link hover:text-blue-600" data-v-97317e6f> 3. ขอบเขตและลักษณะของบริการ </a><a href="#section-4" class="block px-3 py-2 text-sm text-gray-600 rounded-md toc-link hover:text-blue-600" data-v-97317e6f> 4. การสมัครสมาชิกและบัญชีผู้ใช้ </a><a href="#section-5" class="block px-3 py-2 text-sm text-gray-600 rounded-md toc-link hover:text-blue-600" data-v-97317e6f> 5. หน้าที่และความรับผิดชอบ </a><a href="#section-6" class="block px-3 py-2 text-sm text-gray-600 rounded-md toc-link hover:text-blue-600" data-v-97317e6f> 6. การชำระเงิน </a><a href="#section-7" class="block px-3 py-2 text-sm text-gray-600 rounded-md toc-link hover:text-blue-600" data-v-97317e6f> 7. ระบบการให้คะแนนและรีวิว </a><a href="#section-8" class="block px-3 py-2 text-sm text-gray-600 rounded-md toc-link hover:text-blue-600" data-v-97317e6f> 8. ข้อจำกัดความรับผิด </a><a href="#section-9" class="block px-3 py-2 text-sm text-gray-600 rounded-md toc-link hover:text-blue-600" data-v-97317e6f> 9. ทรัพย์สินทางปัญญา </a><a href="#section-10" class="block px-3 py-2 text-sm text-gray-600 rounded-md toc-link hover:text-blue-600" data-v-97317e6f> 10. การระงับและยกเลิกบัญชี </a><a href="#section-11" class="block px-3 py-2 text-sm text-gray-600 rounded-md toc-link hover:text-blue-600" data-v-97317e6f> 11. การแก้ไขเปลี่ยนแปลง </a><a href="#section-12" class="block px-3 py-2 text-sm text-gray-600 rounded-md toc-link hover:text-blue-600" data-v-97317e6f> 12. กฎหมายที่ใช้บังคับ </a><a href="#section-13" class="block px-3 py-2 text-sm text-gray-600 rounded-md toc-link hover:text-blue-600" data-v-97317e6f> 13. การติดต่อ </a></nav></div></div><div class="lg:col-span-3" data-v-97317e6f><div class="p-8 mb-8 bg-white rounded-lg shadow-md" data-v-97317e6f><h1 class="mb-4 text-3xl font-bold text-gray-900" data-v-97317e6f>ข้อตกลงและเงื่อนไขการใช้บริการ</h1><p class="mb-6 text-lg text-gray-600" data-v-97317e6f>(Terms of Service)</p><div class="p-6 rounded-lg highlight-box" data-v-97317e6f><div class="flex items-center mb-2" data-v-97317e6f><svg class="w-6 h-6 mr-2 text-blue-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" data-v-97317e6f><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" data-v-97317e6f></path></svg><span class="text-lg font-semibold text-blue-900" data-v-97317e6f> มีผลบังคับใช้ตั้งแต่วันที่: 8 กรกฎาคม 2568 </span></div><p class="text-sm text-gray-700" data-v-97317e6f> การใช้บริการของเราถือว่าท่านได้อ่านและยอมรับข้อตกลงนี้แล้ว </p></div></div><section id="section-1" class="p-8 mb-6 bg-white rounded-lg shadow-md content-section section-card" data-v-97317e6f><h2 class="mb-4 text-2xl font-bold text-gray-900" data-v-97317e6f>ข้อ 1: บทนำ</h2><p class="mb-4 leading-relaxed text-gray-700" data-v-97317e6f> ยินดีต้อนรับสู่ &quot;ไปนำแหน่&quot; (&quot;แพลตฟอร์ม&quot;) ข้อตกลงและเงื่อนไขการใช้บริการนี้ (&quot;ข้อตกลง&quot;) ถือเป็นสัญญาระหว่างท่าน (&quot;ผู้ใช้&quot;) และแพลตฟอร์ม &quot;ไปนำแหน่&quot; การที่ท่านได้ลงทะเบียน เข้าสู่ระบบ และใช้งานบริการของเรา ถือว่าท่านได้อ่าน ทำความเข้าใจ และยอมรับข้อตกลงทั้งหมดนี้โดยสมบูรณ์แล้ว </p><div class="p-4 border-l-4 border-red-400 rounded-r-lg bg-red-50" data-v-97317e6f><p class="font-medium text-red-700" data-v-97317e6f> หากท่านไม่ยอมรับข้อตกลงนี้ กรุณายุติการใช้งานแพลตฟอร์มของเราทันที </p></div></section><section id="section-2" class="p-8 mb-6 bg-white rounded-lg shadow-md content-section section-card" data-v-97317e6f><h2 class="mb-4 text-2xl font-bold text-gray-900" data-v-97317e6f>ข้อ 2: คำจำกัดความ</h2><div class="space-y-4" data-v-97317e6f><div class="pl-4 border-l-4 border-blue-400" data-v-97317e6f><h3 class="font-semibold text-gray-900" data-v-97317e6f>&quot;แพลตฟอร์ม&quot;</h3><p class="text-gray-700" data-v-97317e6f>หมายถึง เว็บแอปพลิเคชัน &quot;ไปนำแหน่&quot; และบริการอื่นๆ ที่เกี่ยวข้อง</p></div><div class="pl-4 border-l-4 border-green-400" data-v-97317e6f><h3 class="font-semibold text-gray-900" data-v-97317e6f>&quot;บริการ&quot;</h3><p class="text-gray-700" data-v-97317e6f> หมายถึง การที่แพลตฟอร์มทำหน้าที่เป็นตัวกลางทางเทคโนโลยีเพื่อเชื่อมต่อระหว่าง &quot;ผู้ขับขี่&quot; และ &quot;ผู้โดยสาร&quot; ที่มีความต้องการเดินทางในเส้นทางเดียวกันหรือใกล้เคียงกัน </p></div><div class="pl-4 border-l-4 border-purple-400" data-v-97317e6f><h3 class="font-semibold text-gray-900" data-v-97317e6f>&quot;ผู้ใช้&quot;</h3><p class="text-gray-700" data-v-97317e6f> หมายถึง บุคคลทั่วไปที่ลงทะเบียนและสร้างบัญชีบนแพลตฟอร์ม ไม่ว่าจะในฐานะผู้โดยสารหรือผู้ขับขี่ </p></div><div class="pl-4 border-l-4 border-orange-400" data-v-97317e6f><h3 class="font-semibold text-gray-900" data-v-97317e6f>&quot;ผู้ขับขี่&quot; (Driver)</h3><p class="text-gray-700" data-v-97317e6f> หมายถึง ผู้ใช้ที่ลงทะเบียนบนแพลตฟอร์มเพื่อเสนอเส้นทางการเดินทางและแบ่งปันที่นั่งว่างในยานพาหนะส่วนตัวของตน </p></div><div class="pl-4 border-l-4 border-teal-400" data-v-97317e6f><h3 class="font-semibold text-gray-900" data-v-97317e6f>&quot;ผู้โดยสาร&quot; (Passenger)</h3><p class="text-gray-700" data-v-97317e6f> หมายถึง ผู้ใช้ที่ใช้งานแพลตฟอร์มเพื่อค้นหาและทำการจองการเดินทางร่วมกับผู้ขับขี่ </p></div></div></section><section id="section-3" class="p-8 mb-6 bg-white rounded-lg shadow-md content-section section-card" data-v-97317e6f><h2 class="mb-4 text-2xl font-bold text-gray-900" data-v-97317e6f>ข้อ 3: ขอบเขตและลักษณะของบริการ</h2><div class="space-y-4" data-v-97317e6f><div class="p-4 rounded-lg bg-blue-50" data-v-97317e6f><h3 class="mb-2 font-semibold text-blue-900" data-v-97317e6f>3.1</h3><p class="text-gray-700" data-v-97317e6f> &quot;ไปนำแหน่&quot; เป็นเพียงแพลตฟอร์มเทคโนโลยีที่ทำหน้าที่เป็นตัวกลางในการจับคู่เท่านั้น เราไม่ได้เป็นผู้ให้บริการขนส่ง, ไม่ได้เป็นนายจ้างของผู้ขับขี่, ไม่ได้เป็นเจ้าของหรือผู้ควบคุมยานพาหนะ และไม่ได้เสนอบริการเดินทางโดยตรง </p></div><div class="p-4 rounded-lg bg-yellow-50" data-v-97317e6f><h3 class="mb-2 font-semibold text-yellow-900" data-v-97317e6f>3.2</h3><p class="text-gray-700" data-v-97317e6f> สัญญาหรือข้อตกลงใดๆ ที่เกี่ยวกับการเดินทางถือเป็นข้อตกลงโดยตรงระหว่างผู้ขับขี่และผู้โดยสาร &quot;ไปนำแหน่&quot; ไม่มีส่วนรับผิดชอบในข้อตกลงหรือการกระทำใดๆ ที่เกิดขึ้นระหว่างผู้ใช้ </p></div></div></section><section id="section-4" class="p-8 mb-6 bg-white rounded-lg shadow-md content-section section-card" data-v-97317e6f><h2 class="mb-4 text-2xl font-bold text-gray-900" data-v-97317e6f>ข้อ 4: การสมัครสมาชิกและบัญชีผู้ใช้</h2><div class="space-y-4" data-v-97317e6f><div class="flex items-start" data-v-97317e6f><span class="bg-blue-100 text-blue-800 text-sm font-semibold mr-3 px-2.5 py-0.5 rounded" data-v-97317e6f>4.1</span><p class="text-gray-700" data-v-97317e6f> ในการใช้บริการ ท่านต้องลงทะเบียนสร้างบัญชีผู้ใช้และให้ข้อมูลที่เป็นจริง ถูกต้อง และเป็นปัจจุบัน </p></div><div class="flex items-start" data-v-97317e6f><span class="bg-blue-100 text-blue-800 text-sm font-semibold mr-3 px-2.5 py-0.5 rounded" data-v-97317e6f>4.2</span><p class="text-gray-700" data-v-97317e6f> ท่านต้องมีอายุครบตามที่กฎหมายกำหนดในการทำนิติกรรมสัญญา และมีความสามารถในการขับขี่ยานพาหนะตามกฎหมาย (กรณีเป็นผู้ขับขี่) </p></div><div class="flex items-start" data-v-97317e6f><span class="bg-blue-100 text-blue-800 text-sm font-semibold mr-3 px-2.5 py-0.5 rounded" data-v-97317e6f>4.3</span><p class="text-gray-700" data-v-97317e6f> แพลตฟอร์มมีกระบวนการยืนยันตัวตนผ่านรหัส OTP และอาจร้องขอเอกสารเพิ่มเติม เช่น บัตรประชาชน เพื่อความปลอดภัยและความน่าเชื่อถือของชุมชนผู้ใช้ </p></div><div class="flex items-start" data-v-97317e6f><span class="bg-blue-100 text-blue-800 text-sm font-semibold mr-3 px-2.5 py-0.5 rounded" data-v-97317e6f>4.4</span><p class="text-gray-700" data-v-97317e6f> ท่านมีหน้าที่รับผิดชอบในการรักษารหัสผ่านและข้อมูลบัญชีของท่านให้เป็นความลับ และท่านต้องรับผิดชอบต่อกิจกรรมทั้งหมดที่เกิดขึ้นภายใต้บัญชีของท่าน </p></div></div></section><section id="section-5" class="p-8 mb-6 bg-white rounded-lg shadow-md content-section section-card" data-v-97317e6f><h2 class="mb-4 text-2xl font-bold text-gray-900" data-v-97317e6f>ข้อ 5: หน้าที่และความรับผิดชอบของผู้ใช้</h2><div class="space-y-6" data-v-97317e6f><div class="p-6 rounded-lg bg-gray-50" data-v-97317e6f><h3 class="mb-3 text-lg font-semibold text-gray-900" data-v-97317e6f>5.1 สำหรับผู้ใช้ทุกคน:</h3><ul class="space-y-2 text-gray-700" data-v-97317e6f><li class="flex items-start" data-v-97317e6f><span class="mr-2 text-blue-500" data-v-97317e6f>•</span><span data-v-97317e6f>ต้องปฏิบัติต่อผู้ใช้อื่นด้วยความเคารพและให้เกียรติ</span></li><li class="flex items-start" data-v-97317e6f><span class="mr-2 text-blue-500" data-v-97317e6f>•</span><span data-v-97317e6f>ห้ามใช้แพลตฟอร์มในการกระทำที่ผิดกฎหมาย, ฉ้อโกง, คุกคาม หรือสร้างความเดือดร้อนรำคาญ</span></li><li class="flex items-start" data-v-97317e6f><span class="mr-2 text-blue-500" data-v-97317e6f>•</span><span data-v-97317e6f>ต้องใช้ระบบการให้คะแนนและรีวิวตามความเป็นจริงและอย่างสร้างสรรค์</span></li></ul></div><div class="p-6 rounded-lg bg-green-50" data-v-97317e6f><h3 class="mb-3 text-lg font-semibold text-green-900" data-v-97317e6f>5.2 สำหรับผู้โดยสาร (Passenger):</h3><ul class="space-y-2 text-gray-700" data-v-97317e6f><li class="flex items-start" data-v-97317e6f><span class="mr-2 text-green-500" data-v-97317e6f>•</span><span data-v-97317e6f>ต้องให้ข้อมูลจุดนัดพบและจุดหมายปลายทางที่ถูกต้อง</span></li><li class="flex items-start" data-v-97317e6f><span class="mr-2 text-green-500" data-v-97317e6f>•</span><span data-v-97317e6f>ต้องตรงต่อเวลาตามที่ได้นัดหมายไว้กับผู้ขับขี่</span></li><li class="flex items-start" data-v-97317e6f><span class="mr-2 text-green-500" data-v-97317e6f>•</span><span data-v-97317e6f>ต้องรับผิดชอบค่าเดินทางตามที่ได้ตกลงกันไว้</span></li><li class="flex items-start" data-v-97317e6f><span class="mr-2 text-green-500" data-v-97317e6f>•</span><span data-v-97317e6f>มีหน้าที่ดูแลทรัพย์สินส่วนตัวของตนเอง</span></li><li class="flex items-start" data-v-97317e6f><span class="mr-2 text-green-500" data-v-97317e6f>•</span><span data-v-97317e6f>มีสิทธิ์ในการยกเลิกการจองตามเงื่อนไขที่แพลตฟอร์มกำหนด</span></li></ul></div><div class="p-6 rounded-lg bg-orange-50" data-v-97317e6f><h3 class="mb-3 text-lg font-semibold text-orange-900" data-v-97317e6f>5.3 สำหรับผู้ขับขี่ (Driver):</h3><ul class="space-y-2 text-gray-700" data-v-97317e6f><li class="flex items-start" data-v-97317e6f><span class="mr-2 text-orange-500" data-v-97317e6f>•</span><span data-v-97317e6f>ต้องมีใบอนุญาตขับขี่ที่ยังไม่หมดอายุ, เอกสารจดทะเบียนรถยนต์ และประกันภัยภาคบังคับ (พ.ร.บ.) และภาคสมัครใจที่ยังให้ความคุ้มครอง</span></li><li class="flex items-start" data-v-97317e6f><span class="mr-2 text-orange-500" data-v-97317e6f>•</span><span data-v-97317e6f>ยานพาหนะที่ใช้ต้องอยู่ในสภาพที่ปลอดภัยและได้รับการบำรุงรักษาอย่างสม่ำเสมอ</span></li><li class="flex items-start" data-v-97317e6f><span class="mr-2 text-orange-500" data-v-97317e6f>•</span><span data-v-97317e6f>ต้องขับขี่อย่างปลอดภัย ปฏิบัติตามกฎจราจรอย่างเคร่งครัด และไม่ใช้สารเสพติดหรือดื่มแอลกอฮอล์ก่อนหรือขณะขับขี่</span></li><li class="flex items-start" data-v-97317e6f><span class="mr-2 text-orange-500" data-v-97317e6f>•</span><span data-v-97317e6f>ต้องให้ข้อมูลเส้นทาง, วัน-เวลาเดินทาง, และจำนวนที่นั่งว่างที่ถูกต้องแก่ผู้โดยสาร</span></li><li class="flex items-start" data-v-97317e6f><span class="mr-2 text-orange-500" data-v-97317e6f>•</span><span data-v-97317e6f>มีสิทธิ์ในการยอมรับหรือปฏิเสธคำขอร่วมเดินทางจากผู้โดยสาร</span></li></ul></div></div></section><section id="section-6" class="p-8 mb-6 bg-white rounded-lg shadow-md content-section section-card" data-v-97317e6f><h2 class="mb-4 text-2xl font-bold text-gray-900" data-v-97317e6f>ข้อ 6: การชำระเงิน</h2><div class="p-6 border-l-4 rounded-r-lg bg-amber-50 border-amber-400" data-v-97317e6f><p class="text-gray-700" data-v-97317e6f> ค่าใช้จ่ายในการเดินทางเป็นการตกลงกันโดยตรงระหว่างผู้ขับขี่และผู้โดยสาร แพลตฟอร์ม &quot;ไปนำแหน่&quot; ไม่ได้มีส่วนเกี่ยวข้องในการทำธุรกรรมทางการเงินดังกล่าว และจะไม่รับผิดชอบต่อข้อพิพาทใดๆ ที่เกี่ยวกับการชำระเงิน </p></div></section><section id="section-7" class="p-8 mb-6 bg-white rounded-lg shadow-md content-section section-card" data-v-97317e6f><h2 class="mb-4 text-2xl font-bold text-gray-900" data-v-97317e6f>ข้อ 7: ระบบการให้คะแนนและรีวิว</h2><div class="p-6 border-l-4 border-indigo-400 rounded-r-lg bg-indigo-50" data-v-97317e6f><p class="mb-4 text-gray-700" data-v-97317e6f> แพลตฟอร์มสนับสนุนให้มีระบบการให้คะแนนและรีวิวเพื่อสร้างความน่าเชื่อถือในชุมชน </p><div class="p-4 bg-white rounded-lg shadow-sm" data-v-97317e6f><h3 class="mb-3 font-semibold text-indigo-900" data-v-97317e6f>เงื่อนไขการรีวิว:</h3><ul class="space-y-2 text-gray-700" data-v-97317e6f><li class="flex items-start" data-v-97317e6f><span class="mr-2 text-indigo-500" data-v-97317e6f>•</span><span data-v-97317e6f>รีวิวต้องมาจากประสบการณ์จริงเท่านั้น</span></li><li class="flex items-start" data-v-97317e6f><span class="mr-2 text-indigo-500" data-v-97317e6f>•</span><span data-v-97317e6f>ไม่ใช้ถ้อยคำหยาบคายหรือมีเนื้อหาที่ไม่เหมาะสม</span></li><li class="flex items-start" data-v-97317e6f><span class="mr-2 text-indigo-500" data-v-97317e6f>•</span><span data-v-97317e6f>ไม่เป็นการหมิ่นประมาทหรือโจมตีส่วนบุคคล</span></li></ul></div><div class="p-4 mt-4 rounded-lg bg-red-50" data-v-97317e6f><p class="font-medium text-red-700" data-v-97317e6f>⚠️ แพลตฟอร์มขอสงวนสิทธิ์ในการลบรีวิวที่ไม่เป็นไปตามเงื่อนไข</p></div></div></section><section id="section-8" class="p-8 mb-6 bg-white rounded-lg shadow-md content-section section-card" data-v-97317e6f><h2 class="mb-4 text-2xl font-bold text-gray-900" data-v-97317e6f>ข้อ 8: ข้อจำกัดความรับผิดของแพลตฟอร์ม</h2><div class="p-6 border-l-4 border-red-400 rounded-r-lg bg-red-50" data-v-97317e6f><div class="mb-4" data-v-97317e6f><div class="flex items-center mb-2" data-v-97317e6f><svg class="w-6 h-6 mr-2 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" data-v-97317e6f><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-2.5L13.732 4c-.77-.833-1.732-.833-2.5 0L4.268 15.5c-.77.833.192 2.5 1.732 2.5z" data-v-97317e6f></path></svg><h3 class="font-semibold text-red-900" data-v-97317e6f>ข้อจำกัดความรับผิดชอบ</h3></div><p class="mb-4 text-gray-700" data-v-97317e6f> เนื่องจาก &quot;ไปนำแหน่&quot; เป็นเพียงตัวกลางในการเชื่อมต่อ บริการของเราจึงมีให้ในลักษณะ &quot;ตามที่เป็นอยู่&quot; (As Is) </p></div><div class="p-4 bg-white rounded-lg shadow-sm" data-v-97317e6f><h4 class="mb-3 font-semibold text-red-900" data-v-97317e6f>เราขอปฏิเสธความรับผิดในเรื่องต่อไปนี้:</h4><div class="grid grid-cols-1 gap-3 md:grid-cols-2" data-v-97317e6f><div class="flex items-center" data-v-97317e6f><span class="mr-2 text-red-500" data-v-97317e6f>×</span><span class="text-gray-700" data-v-97317e6f>ความเสียหายและการสูญเสีย</span></div><div class="flex items-center" data-v-97317e6f><span class="mr-2 text-red-500" data-v-97317e6f>×</span><span class="text-gray-700" data-v-97317e6f>การบาดเจ็บและอุบัติเหตุ</span></div><div class="flex items-center" data-v-97317e6f><span class="mr-2 text-red-500" data-v-97317e6f>×</span><span class="text-gray-700" data-v-97317e6f>ข้อพิพาทระหว่างผู้ใช้</span></div><div class="flex items-center" data-v-97317e6f><span class="mr-2 text-red-500" data-v-97317e6f>×</span><span class="text-gray-700" data-v-97317e6f>ความล่าช้าในการเดินทาง</span></div></div><p class="mt-3 text-sm text-gray-600" data-v-97317e6f> * เหตุการณ์ใดๆ ที่เกิดขึ้นจากการเดินทางซึ่งอยู่นอกเหนือการควบคุมของเรา </p></div></div></section><section id="section-9" class="p-8 mb-6 bg-white rounded-lg shadow-md content-section section-card" data-v-97317e6f><h2 class="mb-4 text-2xl font-bold text-gray-900" data-v-97317e6f>ข้อ 9: ทรัพย์สินทางปัญญา</h2><div class="p-6 border-l-4 border-purple-400 rounded-r-lg bg-purple-50" data-v-97317e6f><div class="flex items-center mb-4" data-v-97317e6f><svg class="w-6 h-6 mr-2 text-purple-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" data-v-97317e6f><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" data-v-97317e6f></path></svg><h3 class="font-semibold text-purple-900" data-v-97317e6f>ความเป็นเจ้าของทรัพย์สินทางปัญญา</h3></div><div class="p-4 bg-white rounded-lg shadow-sm" data-v-97317e6f><p class="mb-4 text-gray-700" data-v-97317e6f> ทรัพย์สินทางปัญญาทั้งหมดบนแพลตฟอร์ม &quot;ไปนำแหน่&quot; ถือเป็นสิทธิ์ของแพลตฟอร์ม ประกอบด้วย: </p><div class="grid grid-cols-2 gap-4 mb-4 md:grid-cols-4" data-v-97317e6f><div class="text-center" data-v-97317e6f><div class="w-12 h-12 p-3 mx-auto mb-2 bg-purple-100 rounded-full" data-v-97317e6f><svg class="w-6 h-6 text-purple-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" data-v-97317e6f><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M7 4V2a1 1 0 011-1h8a1 1 0 011 1v2M7 4h10l1 14H6L7 4z" data-v-97317e6f></path></svg></div><span class="text-sm text-gray-600" data-v-97317e6f>โลโก้</span></div><div class="text-center" data-v-97317e6f><div class="w-12 h-12 p-3 mx-auto mb-2 bg-purple-100 rounded-full" data-v-97317e6f><svg class="w-6 h-6 text-purple-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" data-v-97317e6f><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M4 5a1 1 0 011-1h14a1 1 0 011 1v2a1 1 0 01-1 1H5a1 1 0 01-1-1V5zM4 13a1 1 0 011-1h6a1 1 0 011 1v6a1 1 0 01-1 1H5a1 1 0 01-1-1v-6zM16 13a1 1 0 011-1h2a1 1 0 011 1v6a1 1 0 01-1 1h-2a1 1 0 01-1-1v-6z" data-v-97317e6f></path></svg></div><span class="text-sm text-gray-600" data-v-97317e6f>การออกแบบ</span></div><div class="text-center" data-v-97317e6f><div class="w-12 h-12 p-3 mx-auto mb-2 bg-purple-100 rounded-full" data-v-97317e6f><svg class="w-6 h-6 text-purple-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" data-v-97317e6f><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" data-v-97317e6f></path></svg></div><span class="text-sm text-gray-600" data-v-97317e6f>ข้อความ</span></div><div class="text-center" data-v-97317e6f><div class="w-12 h-12 p-3 mx-auto mb-2 bg-purple-100 rounded-full" data-v-97317e6f><svg class="w-6 h-6 text-purple-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" data-v-97317e6f><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" data-v-97317e6f></path></svg></div><span class="text-sm text-gray-600" data-v-97317e6f>ซอฟต์แวร์</span></div></div></div><div class="p-4 mt-4 rounded-lg bg-red-50" data-v-97317e6f><p class="font-medium text-red-700" data-v-97317e6f> 🚫 ห้ามมิให้มีการคัดลอก, ดัดแปลง, หรือนำไปใช้โดยไม่ได้รับอนุญาตเป็นลายลักษณ์อักษร </p></div></div></section><section id="section-10" class="p-8 mb-6 bg-white rounded-lg shadow-md content-section section-card" data-v-97317e6f><h2 class="mb-4 text-2xl font-bold text-gray-900" data-v-97317e6f>ข้อ 10: การระงับและยกเลิกบัญชี</h2><div class="p-6 border-l-4 border-orange-400 rounded-r-lg bg-orange-50" data-v-97317e6f><div class="flex items-center mb-4" data-v-97317e6f><svg class="w-6 h-6 mr-2 text-orange-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" data-v-97317e6f><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-2.5L13.732 4c-.77-.833-1.732-.833-2.5 0L4.268 15.5c-.77.833.192 2.5 1.732 2.5z" data-v-97317e6f></path></svg><h3 class="font-semibold text-orange-900" data-v-97317e6f>สิทธิ์ในการระงับบัญชี</h3></div><p class="mb-4 text-gray-700" data-v-97317e6f> &quot;ไปนำแหน่&quot; ขอสงวนสิทธิ์ในการระงับหรือยกเลิกบัญชีของท่านได้ทันทีโดยไม่ต้องแจ้งให้ทราบล่วงหน้า </p><div class="p-4 bg-white rounded-lg shadow-sm" data-v-97317e6f><h4 class="mb-3 font-semibold text-orange-900" data-v-97317e6f>เหตุผลในการระงับบัญชี:</h4><div class="space-y-3" data-v-97317e6f><div class="flex items-start" data-v-97317e6f><span class="bg-orange-100 text-orange-800 text-xs font-medium mr-3 px-2.5 py-1 rounded" data-v-97317e6f>1</span><span class="text-gray-700" data-v-97317e6f>ละเมิดข้อตกลงและเงื่อนไขการใช้บริการ</span></div><div class="flex items-start" data-v-97317e6f><span class="bg-orange-100 text-orange-800 text-xs font-medium mr-3 px-2.5 py-1 rounded" data-v-97317e6f>2</span><span class="text-gray-700" data-v-97317e6f>มีพฤติกรรมที่เป็นอันตรายต่อผู้ใช้อื่น</span></div><div class="flex items-start" data-v-97317e6f><span class="bg-orange-100 text-orange-800 text-xs font-medium mr-3 px-2.5 py-1 rounded" data-v-97317e6f>3</span><span class="text-gray-700" data-v-97317e6f>สร้างความเสี่ยงทางกฎหมายให้กับแพลตฟอร์ม</span></div><div class="flex items-start" data-v-97317e6f><span class="bg-orange-100 text-orange-800 text-xs font-medium mr-3 px-2.5 py-1 rounded" data-v-97317e6f>4</span><span class="text-gray-700" data-v-97317e6f>ได้รับรายงานด้านความปลอดภัยอย่างร้ายแรง</span></div></div></div></div></section><section id="section-11" class="p-8 mb-6 bg-white rounded-lg shadow-md content-section section-card" data-v-97317e6f><h2 class="mb-4 text-2xl font-bold text-gray-900" data-v-97317e6f>ข้อ 11: การแก้ไขเปลี่ยนแปลงข้อตกลง</h2><div class="p-6 border-l-4 border-teal-400 rounded-r-lg bg-teal-50" data-v-97317e6f><div class="flex items-center mb-4" data-v-97317e6f><svg class="w-6 h-6 mr-2 text-teal-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" data-v-97317e6f><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" data-v-97317e6f></path></svg><h3 class="font-semibold text-teal-900" data-v-97317e6f>การอัปเดตข้อตกลง</h3></div><div class="space-y-4" data-v-97317e6f><div class="p-4 bg-white rounded-lg shadow-sm" data-v-97317e6f><p class="mb-3 text-gray-700" data-v-97317e6f> เราขอสงวนสิทธิ์ในการแก้ไขหรือเปลี่ยนแปลงข้อตกลงนี้ได้ทุกเมื่อ การเปลี่ยนแปลงจะมีผลทันทีเมื่อมีการเผยแพร่บนแพลตฟอร์ม </p><div class="flex items-center text-teal-700" data-v-97317e6f><svg class="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24" data-v-97317e6f><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" data-v-97317e6f></path></svg><span class="font-medium" data-v-97317e6f>เราจะพยายามแจ้งให้ท่านทราบถึงการเปลี่ยนแปลงที่สำคัญ</span></div></div><div class="p-4 rounded-lg bg-blue-50" data-v-97317e6f><p class="text-blue-700" data-v-97317e6f><strong data-v-97317e6f>หมายเหตุ:</strong> การที่ท่านยังคงใช้งานแพลตฟอร์มต่อไป ถือว่าท่านยอมรับข้อตกลงฉบับใหม่ </p></div></div></div></section><section id="section-12" class="p-8 mb-6 bg-white rounded-lg shadow-md content-section section-card" data-v-97317e6f><h2 class="mb-4 text-2xl font-bold text-gray-900" data-v-97317e6f>ข้อ 12: กฎหมายที่ใช้บังคับ</h2><div class="p-6 border-l-4 border-gray-400 rounded-r-lg bg-gray-50" data-v-97317e6f><div class="flex items-center mb-4" data-v-97317e6f><svg class="w-6 h-6 mr-2 text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" data-v-97317e6f><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M3 6l3 1m0 0l-3 9a5.002 5.002 0 006.001 0M6 7l3 9M6 7l6-2m6 2l3-1m-3 1l-3 9a5.002 5.002 0 006.001 0M18 7l3 9m-3-9l-6-2m0-2v2m0 16V5m0 16H9m3 0h3" data-v-97317e6f></path></svg><h3 class="font-semibold text-gray-900" data-v-97317e6f>เขตอำนาจศาล</h3></div><div class="p-4 text-center bg-white rounded-lg shadow-sm" data-v-97317e6f><div class="mb-3" data-v-97317e6f><svg class="w-12 h-12 mx-auto text-red-500" fill="none" stroke="currentColor" viewBox="0 0 24 24" data-v-97317e6f><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M3 21v-4m0 0V5a2 2 0 012-2h6.5l1 1H21l-3 6 3 6h-8.5l-1-1H5a2 2 0 00-2 2zm9-13.5V9" data-v-97317e6f></path></svg></div><p class="mb-2 text-lg font-semibold text-gray-900" data-v-97317e6f> ข้อตกลงนี้อยู่ภายใต้การบังคับใช้และตีความตาม </p><p class="text-2xl font-bold text-red-600" data-v-97317e6f>กฎหมายแห่งราชอาณาจักรไทย</p></div></div></section><section id="section-13" class="p-8 mb-6 bg-white rounded-lg shadow-md content-section section-card" data-v-97317e6f><h2 class="mb-4 text-2xl font-bold text-gray-900" data-v-97317e6f>ข้อ 13: การติดต่อ</h2><div class="p-6 border-l-4 border-green-400 rounded-r-lg bg-green-50" data-v-97317e6f><div class="flex items-center mb-4" data-v-97317e6f><svg class="w-6 h-6 mr-2 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" data-v-97317e6f><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" data-v-97317e6f></path></svg><h3 class="font-semibold text-green-900" data-v-97317e6f>ติดต่อเรา</h3></div><div class="p-4 bg-white rounded-lg shadow-sm" data-v-97317e6f><p class="mb-4 text-gray-700" data-v-97317e6f> หากท่านมีคำถามเกี่ยวกับข้อตกลงและเงื่อนไขการใช้บริการนี้ กรุณาติดต่อเราผ่านทาง: </p><div class="grid grid-cols-1 gap-4 md:grid-cols-2" data-v-97317e6f><div class="flex items-center p-3 rounded-lg bg-gray-50" data-v-97317e6f><svg class="w-5 h-5 mr-3 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" data-v-97317e6f><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2z" data-v-97317e6f></path></svg><div data-v-97317e6f><div class="font-medium text-gray-900" data-v-97317e6f>อีเมล</div><div class="text-sm text-gray-600" data-v-97317e6f>support@painahae.com</div></div></div><div class="flex items-center p-3 rounded-lg bg-gray-50" data-v-97317e6f><svg class="w-5 h-5 mr-3 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" data-v-97317e6f><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M3 5a2 2 0 012-2h3.28a1 1 0 01.948.684l1.498 4.493a1 1 0 01-.502 1.21l-2.257 1.13a11.042 11.042 0 005.516 5.516l1.13-2.257a1 1 0 011.21-.502ล4.493 1.498a1 1 0 01.684.949V19a2 2 0 01-2 2h-1C9.716 21 3 14.284 3 6V5z" data-v-97317e6f></path></svg><div data-v-97317e6f><div class="font-medium text-gray-900" data-v-97317e6f>โทรศัพท์</div><div class="text-sm text-gray-600" data-v-97317e6f>02-XXX-XXXX</div></div></div></div></div></div></section></div></div></div>',1))]))}},C=c(w,[["__scopeId","data-v-97317e6f"]]);export{C as default};
